import React, { useEffect, useState } from 'react';
import {
  Box,
  Button,
  Checkbox,
  FormControl,
  FormControlLabel,
  Grid,
  InputAdornment,
  InputLabel,
  MenuItem,
  Paper,
  Select,
  Stack,
  TextField,
  Typography,
} from '@mui/material';
import AccessTimeRoundedIcon from '@mui/icons-material/AccessTimeRounded';
import AutoAwesomeRoundedIcon from '@mui/icons-material/AutoAwesomeRounded';
import LocalDiningRoundedIcon from '@mui/icons-material/LocalDiningRounded';
import { CUISINES } from '../constants';
import { glassPanelSx } from '../utils/glassPanel';

function emptyForm() {
  return {
    name: '',
    ingredients: '',
    steps: '',
    cookingTime: '',
    cuisine: 'Indian',
    isFavorite: false,
  };
}

export default function RecipeForm({ onSave, editing, onCancel, busy }) {
  const [form, setForm] = useState(emptyForm());

  useEffect(() => {
    if (editing) {
      setForm({
        ...editing,
        cookingTime: String(editing.cookingTime),
      });
      return;
    }
    setForm(emptyForm());
  }, [editing]);

  const handleChange = (event) => {
    const { name, value, type, checked } = event.target;
    setForm((prev) => ({ ...prev, [name]: type === 'checkbox' ? checked : value }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    onSave({
      ...form,
      cookingTime: Number(form.cookingTime),
    });
  };

  return (
    <Paper elevation={0} sx={{ p: { xs: 2, md: 3 }, borderRadius: 4, ...glassPanelSx() }}>
      <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
        <AutoAwesomeRoundedIcon color="primary" />
        <Typography variant="h6" fontWeight={700}>
          {editing ? 'Update Recipe' : 'Create Recipe'}
        </Typography>
      </Stack>

      <Box component="form" onSubmit={handleSubmit}>
        <Grid container spacing={2}>
          <Grid item xs={12} md={6}>
            <TextField
              label="Recipe Name"
              name="name"
              value={form.name}
              onChange={handleChange}
              fullWidth
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <LocalDiningRoundedIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            />
          </Grid>

          <Grid item xs={12} md={6}>
            <FormControl fullWidth>
              <InputLabel>Cuisine</InputLabel>
              <Select name="cuisine" value={form.cuisine} label="Cuisine" onChange={handleChange}>
                {CUISINES.map((cuisine) => (
                  <MenuItem key={cuisine} value={cuisine}>
                    {cuisine}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>

          <Grid item xs={12} md={6}>
            <TextField
              label="Cooking Time (minutes)"
              name="cookingTime"
              value={form.cookingTime}
              onChange={handleChange}
              type="number"
              inputProps={{ min: 1 }}
              fullWidth
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <AccessTimeRoundedIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            />
          </Grid>

          <Grid item xs={12} md={6}>
            <FormControlLabel
              control={<Checkbox name="isFavorite" checked={form.isFavorite} onChange={handleChange} color="error" />}
              label="Pin as Favorite"
              sx={{ mt: 0.5 }}
            />
          </Grid>

          <Grid item xs={12}>
            <TextField
              label="Ingredients"
              name="ingredients"
              value={form.ingredients}
              onChange={handleChange}
              fullWidth
              required
              multiline
              minRows={2}
              placeholder="Example: 2 tomatoes, olive oil, basil"
            />
          </Grid>

          <Grid item xs={12}>
            <TextField
              label="Steps"
              name="steps"
              value={form.steps}
              onChange={handleChange}
              fullWidth
              required
              multiline
              minRows={3}
              placeholder="Describe the method in clear steps"
            />
          </Grid>

          <Grid item xs={12}>
            <Stack direction="row" spacing={1.5}>
              <Button type="submit" variant="contained" disabled={busy}>
                {editing ? 'Save Changes' : 'Add Recipe'}
              </Button>
              {editing && (
                <Button variant="outlined" onClick={onCancel} disabled={busy}>
                  Cancel
                </Button>
              )}
            </Stack>
          </Grid>
        </Grid>
      </Box>
    </Paper>
  );
}
